class LinkedList {
  constructor() {
    this.head = null;
    this.size = 0;
  }
  add(element) {
    const node = new Node(element); // Create a node before adding
    let current;
    if (this.head === null)
      //For first element
      this.head = node;
    else {
      // Iterate till the last item and add value
      current = this.head;
      while (current.next) {
        current = current.next;
      }
      current.next = node;
    }
    this.size++;
  }
  printList() {
    let curr = this.head;
    let str = '';
    while (curr) {
      str += curr.element + ' ';
      curr = curr.next;
    }
    console.log(str);
  }
  reverseList() {
    let current = this.head;
    let prev = null;
    let next = null;
    while (current != null) {
      next = current.next;
      current.next = prev;
      prev = current;
      current = next;
    }
    // The prev will be pointing to last node, which you will point // to head now so if we start printing from head, list will be
    // reversed
    this.head = prev;
  }
}

